<?php $editing = !empty($editLead); ?>
<div class="page-header"><div><h2>Leads</h2><p>Prospect intake, qualification, assignment, AI scoring, and client conversion.</p></div></div>
<div class="grid-two">
<div class="card"><h3><?= $editing ? 'Edit Lead' : 'Add Lead' ?></h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="<?= $editing ? 'update' : 'create' ?>"><?php if ($editing): ?><input type="hidden" name="id" value="<?= e((string)$editLead['id']) ?>"><?php endif; ?><input name="lead_name" placeholder="Lead Name" value="<?= e($editLead['lead_name'] ?? '') ?>" required><input name="company_name" placeholder="Company" value="<?= e($editLead['company_name'] ?? '') ?>"><input name="email" placeholder="Email" value="<?= e($editLead['email'] ?? '') ?>"><input name="phone" placeholder="Phone" value="<?= e($editLead['phone'] ?? '') ?>"><input name="source_name" placeholder="Lead Source" value="<?= e($editLead['source_name'] ?? '') ?>"><select name="stage"><?php foreach (['New','Contacted','Qualified','Proposal','Converted','Lost'] as $stage): ?><option value="<?= e($stage) ?>" <?= (($editLead['stage'] ?? 'New')===$stage)?'selected':''; ?>><?= e($stage) ?></option><?php endforeach; ?></select><select name="assigned_user_id"><option value="">Assigned Owner</option><?php foreach ($assignableUsers as $user): ?><option value="<?= e((string)$user['id']) ?>" <?= ((string)($editLead['assigned_user_id'] ?? '') === (string)$user['id']) ? 'selected' : '' ?>><?= e($user['full_name']) ?> · <?= e($user['role']) ?></option><?php endforeach; ?></select><textarea name="notes" placeholder="Notes"><?= e($editLead['notes'] ?? '') ?></textarea><div class="actions"><button type="submit"><?= $editing ? 'Save Changes' : 'Create Lead' ?></button><?php if ($editing): ?><a class="btn-muted" href="index.php?page=leads">Cancel</a><?php endif; ?></div></form></div>
<div class="card"><h3>Lead Queue</h3><table><thead><tr><th>Lead</th><th>Source</th><th>Stage</th><th>AI Score</th><th>Assigned</th><th></th></tr></thead><tbody><?php foreach ($leads as $row): ?><tr><td><?= e($row['lead_name']) ?><div class="muted"><?= e($row['company_name']) ?> · <?= e($row['email']) ?></div></td><td><?= e($row['source_name']) ?></td><td><span class="tag"><?= e($row['stage']) ?></span></td><td><?= e((string)($row['ai_score'] ?? 0)) ?></td><td><?= e($row['assigned_to']) ?></td><td class="table-actions"><a href="index.php?page=leads&id=<?= e((string)$row['id']) ?>">Edit</a><?php if ($row['stage'] !== 'Converted'): ?><form method="post"><?= csrf_field() ?><input type="hidden" name="action" value="convert"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button type="submit">Convert</button></form><?php endif; ?><?php if (App\Core\Auth::can('leads','delete')): ?><form method="post" onsubmit="return confirm('Delete this lead?');"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button class="btn-danger" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
</div>
